import type { ReactNode } from 'react';
import { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { 
  signIn, 
  signUp, 
  signOut, 
  getCurrentUser,
  confirmSignUp,
  fetchUserAttributes
} from 'aws-amplify/auth';
import { generateClient } from 'aws-amplify/api';
import type { Couple, Expense, Settlement, User, Balance, HistoryConnection, HistoryQueryOptions } from '../types';
import { calculateBalance } from '../utils/helpers';

// GraphQL query for getCoupleHistory (will be generated by amplify codegen)
const getCoupleHistory = /* GraphQL */ `
  query GetCoupleHistory(
    $coupleId: ID!
    $limit: Int
    $nextToken: String
    $typeFilter: String
    $categoryFilter: String
    $paidByFilter: String
  ) {
    getCoupleHistory(
      coupleId: $coupleId
      limit: $limit
      nextToken: $nextToken
      typeFilter: $typeFilter
      categoryFilter: $categoryFilter
      paidByFilter: $paidByFilter
    ) {
      items {
        id
        type
        date
        createdAt
        amount
        paidBy
        description
        category
        splitType
        partner1Share
        partner2Share
        paidTo
        note
      }
      nextToken
      totalCount
    }
  }
`;

// Trusted mutations - these go through the Lambda write service
const createCoupleTrustedMutation = /* GraphQL */ `
  mutation CreateCoupleTrusted($input: CreateCoupleInput!) {
    createCoupleTrusted(input: $input) {
      success
      error
      clientMutationId
      couple {
        id
        owners
        name
        partner1Id
        partner1Name
        partner1Email
        partner2Id
        partner2Name
        partner2Email
        inviteCode
        defaultSplitPercent
        expenseCount
        settlementCount
        partner1TotalPaid
        partner2TotalPaid
        partner1TotalOwes
        partner2TotalOwes
        netBalance
        lastCalculatedAt
        createdAt
        updatedAt
      }
    }
  }
`;

